inline flatbuffers::Offset<SBallShot> CreateSBallShot(
    flatbuffers::FlatBufferBuilder &_fbb,
    int32_t owner = 0,
    F4PACKET::SHOT_TYPE shottype = F4PACKET::SHOT_TYPE::shotType_none,
    const TB::SVector3 *positionball = 0,
    const TB::SVector3 *positionowner = 0,
    float time = 0.0f,
    int32_t ballnumber = 0,
    F4PACKET::SHOT_THROW shotthrow = F4PACKET::SHOT_THROW::low,
    F4PACKET::SHOT_BOUND shotbound = F4PACKET::SHOT_BOUND::success_clean,
    float targetreachtime = 0.0f,
    bool ownhanded = false,
    bool wideopen = false,
    float bonus = 0.0f,
    float bonuspassive = 0.0f,
    float bonussignature = 0.0f,
    float bonusnicepass = 0.0f,
    float bonusanklebreakesuccess = 0.0f,
    int32_t signaturekey = 0,
    bool nicepasshindrance = false,
    int32_t nicepasspasser = 0,
    int32_t point = 0,
    int32_t index = 0,
    F4PACKET::SKILL_INDEX skillindex = F4PACKET::SKILL_INDEX::skill_none,
    flatbuffers::Offset<flatbuffers::Vector<int32_t>> medalindices = 0,
    bool enabledribble = false,
    flatbuffers::Offset<flatbuffers::Vector<const F4PACKET::SHindrance *>> hindrances = 0,
    F4PACKET::BB_STATE bbstate = F4PACKET::BB_STATE::firstState,
    bool bankshot = false,
    float successrate = 0.0f,
    bool success = false,
    int32_t potentialfxlevel = 0) {
  SBallShotBuilder builder_(_fbb);
  builder_.add_potentialfxlevel(potentialfxlevel);
  builder_.add_successrate(successrate);
  builder_.add_hindrances(hindrances);
  builder_.add_medalindices(medalindices);
  builder_.add_skillindex(skillindex);
  builder_.add_index(index);
  builder_.add_point(point);
  builder_.add_nicepasspasser(nicepasspasser);
  builder_.add_signaturekey(signaturekey);
  builder_.add_bonusanklebreakesuccess(bonusanklebreakesuccess);
  builder_.add_bonusnicepass(bonusnicepass);
  builder_.add_bonussignature(bonussignature);
  builder_.add_bonuspassive(bonuspassive);
  builder_.add_bonus(bonus);
  builder_.add_targetreachtime(targetreachtime);
  builder_.add_ballnumber(ballnumber);
  builder_.add_time(time);
  builder_.add_positionowner(positionowner);
  builder_.add_positionball(positionball);
  builder_.add_owner(owner);
  builder_.add_success(success);
  builder_.add_bankshot(bankshot);
  builder_.add_bbstate(bbstate);
  builder_.add_enabledribble(enabledribble);
  builder_.add_nicepasshindrance(nicepasshindrance);
  builder_.add_wideopen(wideopen);
  builder_.add_ownhanded(ownhanded);
  builder_.add_shotbound(shotbound);
  builder_.add_shotthrow(shotthrow);
  builder_.add_shottype(shottype);
  return builder_.Finish();
}

inline flatbuffers::Offset<SBallShot> CreateSBallShotDirect(
    flatbuffers::FlatBufferBuilder &_fbb,
    int32_t owner = 0,
    F4PACKET::SHOT_TYPE shottype = F4PACKET::SHOT_TYPE::shotType_none,
    const TB::SVector3 *positionball = 0,
    const TB::SVector3 *positionowner = 0,
    float time = 0.0f,
    int32_t ballnumber = 0,
    F4PACKET::SHOT_THROW shotthrow = F4PACKET::SHOT_THROW::low,
    F4PACKET::SHOT_BOUND shotbound = F4PACKET::SHOT_BOUND::success_clean,
    float targetreachtime = 0.0f,
    bool ownhanded = false,
    bool wideopen = false,
    float bonus = 0.0f,
    float bonuspassive = 0.0f,
    float bonussignature = 0.0f,
    float bonusnicepass = 0.0f,
    float bonusanklebreakesuccess = 0.0f,
    int32_t signaturekey = 0,
    bool nicepasshindrance = false,
    int32_t nicepasspasser = 0,
    int32_t point = 0,
    int32_t index = 0,
    F4PACKET::SKILL_INDEX skillindex = F4PACKET::SKILL_INDEX::skill_none,
    const std::vector<int32_t> *medalindices = nullptr,
    bool enabledribble = false,
    const std::vector<F4PACKET::SHindrance> *hindrances = nullptr,
    F4PACKET::BB_STATE bbstate = F4PACKET::BB_STATE::firstState,
    bool bankshot = false,
    float successrate = 0.0f,
    bool success = false,
    int32_t potentialfxlevel = 0) {
  auto medalindices__ = medalindices ? _fbb.CreateVector<int32_t>(*medalindices) : 0;
  auto hindrances__ = hindrances ? _fbb.CreateVectorOfStructs<F4PACKET::SHindrance>(*hindrances) : 0;
  return F4PACKET::CreateSBallShot(
      _fbb,
      owner,
      shottype,
      positionball,
      positionowner,
      time,
      ballnumber,
      shotthrow,
      shotbound,
      targetreachtime,
      ownhanded,
      wideopen,
      bonus,
      bonuspassive,
      bonussignature,
      bonusnicepass,
      bonusanklebreakesuccess,
      signaturekey,
      nicepasshindrance,
      nicepasspasser,
      point,
      index,
      skillindex,
      medalindices__,
      enabledribble,
      hindrances__,
      bbstate,
      bankshot,
      successrate,
      success,
      potentialfxlevel);
}

flatbuffers::Offset<SBallShot> CreateSBallShot(flatbuffers::FlatBufferBuilder &_fbb, const SBallShotT *_o, const flatbuffers::rehasher_function_t *_rehasher = nullptr);

